var e=[{id:`L2_1`,type:`dialog`,speaker:`LEESOOYEON_COFFIN_NULL_NULL`,text:{KOREA:`이걸로 의무교육은 끝났습니다.`,JPN:`これに義務教育は終わりました。`,ENG:`That's it for all the compulsory training sessions.`,TWN:`義務教育到此結束。`},stage:{bg:`NEWTOWN_NIGHT`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEESOOYEON_COFFIN_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`...... 드디어 끝이로군.`,JPN:`......ついに終りだな。`,ENG:`...... Finally.`,TWN:`……終於結束了。`},stage:{bg:`NEWTOWN_NIGHT`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`뭐 조금 귀찮긴 했지만, 꽤 도움이 된 것 같기도......`,JPN:`何少し面倒であったが、かなり役に立ったようだったり......`,ENG:`It was a bit annoying, but I guess it helped...`,TWN:`雖然有點麻煩，但好像也挺有用的……`},stage:{bg:`NEWTOWN_NIGHT`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`LEESOOYEON_COFFIN_NULL_NULL`,text:{KOREA:`아, 그리고 복귀 후엔 필기테스트를 진행할 예정이니 잘 기억해 두시기 바랍니다.`,JPN:`あ、そして復帰後には筆記テストを進行する予定だからよく記憶しておいてほしいです。`,ENG:`Oh, and keep in mind that we will proceed with the written test when you return.`,TWN:`啊對了，之後的筆試請您千萬不要忘了。`},stage:{bg:`NEWTOWN_NIGHT`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEESOOYEON_COFFIN_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`필기......테스트? 설마 나보고 시험을 보란 소리는 아니겠지?`,JPN:`筆記......テスト?まさか私に試験を受けるという音はないだろう?`,ENG:`Written... test? You seriously want to test me on this?`,TWN:`筆……試？難不成妳還要我去參加考試？`},stage:{bg:`NEWTOWN_NIGHT`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`LEESOOYEON_COFFIN_NULL_NULL`,text:{KOREA:`참고로 컴퓨터 사인펜은 개인지참입니다.`,JPN:`参考でコンピュータサインペンは個人持ちこみです。`,ENG:`FYI, you must bring your own marker.`,TWN:`順帶一提，電子筆要自己帶。`},stage:{bg:`NEWTOWN_NIGHT`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEESOOYEON_COFFIN_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`야! 이수연......!`,JPN:`やあ!イスルギ・チカゲ......!`,ENG:`Hey! Lee Sooyeon!`,TWN:`喂！李秀妍……！`},stage:{bg:`NEWTOWN_NIGHT`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NULL_NULL`,face:`UNIT_HATE`},R:null}}}];export{e as default};